import json
import urllib.request
import urllib.error

URL = "http://127.0.0.1:8000/api/document-analyze"
API_KEY = "sk_track2_987654321"

SAMPLES = [
    {
        "fileName": "sample1-Technology_Industry_Analysis.pdf",
        "fileType": "pdf",
        "fileBase64": ""
    },
    {
        "fileName": "sample2-Cybersecurity_Incident_Report.docx",
        "fileType": "docx",
        "fileBase64": ""
    },
    {
        "fileName": "sample3.jpg",
        "fileType": "image",
        "fileBase64": ""
    },
]

def test(sample):
    print(f"\n{'='*60}")
    print(f"FILE : {sample['fileName']}")
    print(f"TYPE : {sample['fileType'].upper()}")
    print('='*60)
    try:
        data = json.dumps(sample).encode("utf-8")
        req = urllib.request.Request(
            URL,
            data=data,
            headers={
                "Content-Type": "application/json",
                "x-api-key": API_KEY
            },
            method="POST"
        )
        with urllib.request.urlopen(req, timeout=180) as resp:
            result = json.loads(resp.read().decode())
        print(f"STATUS       : {result.get('status')}")
        print(f"SUMMARY      : {result.get('summary','')[:200]}")
        print(f"SENTIMENT    : {result.get('sentiment')}")
        print(f"DOC TYPE     : {result.get('document_type')}")
        ents = result.get("entities", {})
        for k, v in ents.items():
            if v:
                print(f"{k.upper():13s}: {', '.join(str(x) for x in v[:5])}")
        kp = result.get("key_phrases", [])
        if kp:
            print(f"KEY PHRASES  : {', '.join(kp[:5])}")
        print(f"PROCESSING   : {result.get('processing_time_seconds')}s")
    except urllib.error.HTTPError as e:
        print(f"HTTP ERROR {e.code}: {e.read().decode()}")
    except Exception as e:
        print(f"ERROR: {e}")

if __name__ == "__main__":
    print("AI Document Analysis API - Test Runner")
    print("Make sure server is running: uvicorn main:app --reload")
    for s in SAMPLES:
        test(s)
    print("\nDone!")
